1	/**
2	 * POST /api/chat — public, rate-limited, streaming chat over the corpus.
3	 *
4	 * Pipeline:
5	 *   1. zod-validate body
6	 *   2. rate-limit by IP (or "anon" if absent)
7	 *   3. retrieve top-k corpus chunks for the latest user message
8	 *   4. assemble persona + retrieved context into the system prompt
9	 *   5. open the Anthropic stream and pipe tokens out as SSE
10	 *   6. emit a `meta` event with citations + usage when the model is done
11	 *
12	 * Streaming is intentionally held for up to ~200ms while retrieval runs;
13	 * after that the response is flushed token-by-token as soon as Claude emits
14	 * a delta. Sessions are NOT persisted server-side.
15	 */
16	import { NextRequest } from "next/server";
17	
18	import {
19	  AnthropicError,
20	  getAnthropicClient,
21	} from "@/lib/llm/anthropicClient";
22	import { chatRequestSchema, type ChatMetaPayload } from "@/lib/llm/chatTypes";
23	import { buildPersona } from "@/lib/llm/persona";
24	import { assemblePrompt } from "@/lib/llm/promptAssembly";
25	import {
26	  ANON_KEY,
27	  checkRateLimit,
28	  deriveKey,
29	} from "@/lib/llm/rateLimiter";
30	import { retrieve } from "@/lib/llm/retriever";
31	
32	export const runtime = "nodejs";
33	export const dynamic = "force-dynamic";
34	
35	const SSE_HEADERS = {
36	  "Content-Type": "text/event-stream; charset=utf-8",
37	  "Cache-Control": "no-cache, no-transform",
38	  Connection: "keep-alive",
39	  "X-Accel-Buffering": "no",
40	};
41	
42	export async function POST(req: NextRequest): Promise<Response> {
43	  // 1. Parse + validate JSON body.
44	  let body: unknown;
45	  try {
46	    body = await req.json();
47	  } catch {
48	    return jsonError(400, "invalid_json", "request body must be JSON");
49	  }
50	  const parsed = chatRequestSchema.safeParse(body);
51	  if (!parsed.success) {
52	    return jsonError(
53	      400,
54	      "invalid_request",
55	      parsed.error.issues.map((i) => i.message).join("; ")
56	    );
57	  }
58	  const { messages, topicHints } = parsed.data;
59	  const last = messages[messages.length - 1];
60	
61	  // 2. Rate limit.
62	  const fallbackIp =
63	    (req as unknown as { ip?: string | null }).ip ?? null;
64	  const key = deriveKey(req.headers, fallbackIp);
65	  const rl = await checkRateLimit(key);
66	  if (!rl.allowed) {
67	    const retryAfter = Math.max(1, Math.ceil(rl.resetMs / 1000));
68	    return new Response(
69	      JSON.stringify({
70	        error: "rate_limited",
71	        detail:
72	          rl.limited === "day"
73	            ? "daily request limit reached"
74	            : "hourly request limit reached",
75	        remaining: rl.remaining,
76	        retryAfterSeconds: retryAfter,
77	      }),
78	      {
79	        status: 429,
80	        headers: {
81	          "Content-Type": "application/json",
82	          "Retry-After": String(retryAfter),
83	        },
84	      }
85	    );
86	  }
87	
88	  if (key === ANON_KEY) {
89	    // Defensive log so prod can see when the IP-derivation fallback fired.
90	    console.warn("[/api/chat] no IP available; using anon bucket");
91	  }
